#include<bits/stdc++.h>
using namespace std;
long long n,a[1000009],ma=INT_MIN;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    for(int i=1;i<=n-1;i++){
        for(int j=i+1;j<=n;j++){
            ma=max(ma,(a[i]&a[j]));
        }
    }
    cout<<ma;
    return 0;
}
